    ))
  })

  observeEvent(input$login_button, {
    if (input$password == "9999") {
      values$logged_in <- TRUE
      values$username  <- stringr::str_to_lower(input$username)
      removeModal()
    } else {
      showModal(modalDialog(
        title = "Error",
        "Incorrect password, please try again.",
        easyClose = TRUE,
        footer = modalButton("Close")
      ))
    }
  })

  # ================
  # 2. PURGE LOGIC
  # ================
  purge_image <- function(img_key, user, conn) {
    update_data <- list(
      '$set' = list(
        purged    = TRUE,
        purgedBy  = user,
        purgeDate = Sys.time()
      )
    )
    conn$update(
      query  = to_json_query(list(key = img_key)),
      update = to_json_query(update_data)
    )
    message(paste("Purged image:", img_key, "by user:", user))
  }

  # ================
  # 3. ELO SCORING WITH IMPROVEMENTS
  # ================
  update_scores <- function(winner_key, loser_key, conn) {
    winner_data <- conn$find(query = to_json_query(list(key = winner_key)))
    loser_data  <- conn$find(query = to_json_query(list(key = loser_key)))

    if (nrow(winner_data) == 0 || nrow(loser_data) == 0) {
      stop("Winner or loser data not found in the database")
    }

    # Expected scores
    e_winner <- 1 / (1 + 10 ^ ((loser_data$elo[1] - winner_data$elo[1]) / 400))
    e_loser  <- 1 - e_winner

    # IMPROVEMENT 1: Modified K-factor with minimum values
    k_winner <- max(16, 32 / (1 + winner_data$total[1] / 20))
    k_loser  <- max(16, 32 / (1 + loser_data$total[1] / 20))

    # IMPROVEMENT 2: Upset bonus for underdogs
    if (loser_data$elo[1] > winner_data$elo[1] + 200) {
      k_winner <- k_winner * 1.5  # 50% bonus for major upsets
      cat("Upset bonus applied! Underdog beat favorite by", 
          loser_data$elo[1] - winner_data$elo[1], "ELO points\n")
    }

    new_winner_elo <- winner_data$elo[1] + k_winner * (1 - e_winner)
    new_loser_elo  <- loser_data$elo[1]  - k_loser * e_loser

    # Update winner
    winner_update <- list(
      '$inc' = list(
        wins  = 1,
        total = 1
      ),
      '$set' = list(
        elo = new_winner_elo,
        last_updated = Sys.time()
      )
    )
    conn$update(query = to_json_query(list(key = winner_key)), 
                update = to_json_query(winner_update))

    # Update loser
    loser_update <- list(
      '$inc' = list(
        total = 1
      ),
      '$set' = list(
        elo = new_loser_elo,
        last_updated = Sys.time()
      )
    )
    conn$update(query = to_json_query(list(key = loser_key)), 
                update = to_json_query(loser_update))

    cat("Updated Winner ELO:", new_winner_elo, "(K:", k_winner, ")\n")
    cat("Updated Loser ELO:", new_loser_elo, "(K:", k_loser, ")\n")

    # IMPROVEMENT 5: Progressive exposure for winning new images
    if (winner_data$total[1] < 10 && winner_data$wins[1] / max(winner_data$total[1], 1) > 0.6) {
      # Winning new image gets extended protection
      values$forcedImage <- winner_key
      values$forcedCount <- 0  # Reset counter
      cat("Progressive exposure: Forcing", winner_key, "due to high win rate\n")
    }
  }

  # ================
  # 4. DECISION LOGS
  # ================
  log_decision <- function(user, image1, image2, winner, left_liked, right_liked, conn, reason = NULL) {
    decision <- list(
      user         = user,
      image1       = image1,
      image2       = image2,
      winner       = winner,            # numeric: 1 or 2, or NULL if no rating
      left_liked   = left_liked,
      right_liked  = right_liked,
      reason       = reason,            # e.g. "both purged" or "purged item chosen" etc.
      date         = Sys.time()
    )
    conn$insert(decision)
  }

  # ================
  # 5. HELPER FUNCTIONS TO ADVANCE
  # ================
  # Move to next pair, resetting flags
  advance_to_next_pair <- function() {
    values$left_liked   <- FALSE
    values$right_liked  <- FALSE
    values$purged_left  <- FALSE
    values$purged_right <- FALSE
    current_pair(get_next_image_pair())
  }

  # ================
  # 6. GET NEXT PAIR WITH IMPROVEMENTS
  # ================
  get_next_image_pair <- function() {
    # Return documents which are NOT purged
    documents <- conn$find(
      query = '{"purged": {"$ne": true}}',
      fields = '{"key": 1, "elo": 1, "total": 1, "wins": 1, "last_updated": 1}'
    )

    if (!is.data.frame(documents) || nrow(documents) < 2) {
      # Not enough images to compare
      showModal(modalDialog(
        title = "No more images",
        "There are not enough un-purged images left to compare.",
        easyClose = TRUE
      ))
      return(NULL)
    }

    if (!all(c("key", "elo", "total", "wins") %in% names(documents))) {
      stop("Expected 'documents' to have columns: key, elo, total, wins.")
    }

    # IMPROVEMENT 4: Apply freshness decay
    if ("last_updated" %in% names(documents)) {
      documents$last_updated <- as.POSIXct(documents$last_updated)
      days_since_update <- as.numeric(difftime(Sys.time(), documents$last_updated, units = "days"))
      freshness_penalty <- pmin(days_since_update / 30, 0.1)  # Max 10% penalty
      documents$adjusted_elo <- documents$elo * (1 - freshness_penalty)
    } else {
      documents$adjusted_elo <- documents$elo
    }

    # -- 1) If forcing a "new" image for up to 15 comparisons
    if (!is.null(values$forcedImage) && values$forcedCount < 15) {
      forced_doc <- documents[documents$key == values$forcedImage, , drop = FALSE]
      if (nrow(forced_doc) == 0) {
        # forced image is gone or purged
        values$forcedImage <- NULL
        values$forcedCount <- 0
      } else {
        # pick a random other from docs
        other_docs <- documents[documents$key != values$forcedImage, , drop = FALSE]
        # Exclude recent to avoid spam
        other_docs <- other_docs[!(other_docs$key %in% values$recent_images), , drop = FALSE]
        if (nrow(other_docs) < 1) {
          # reset recent
          values$recent_images <- character()
          other_docs <- documents[documents$key != values$forcedImage, , drop = FALSE]
        }
        idx2 <- sample(seq_len(nrow(other_docs)), 1)
        right <- other_docs$key[idx2]
        left  <- values$forcedImage

        values$forcedCount <- values$forcedCount + 1

        # update recent
        values$recent_images <- c(values$recent_images, left, right)
        if (length(values$recent_images) > 10) {
          values$recent_images <- tail(values$recent_images, 10)
        }

        return(list(left = left, right = right))
      }
    }

    # -- 2) If not forcing, look for new images (total < 5)
    new_candidates <- documents[documents$total < 5, ]
    if (nrow(new_candidates) > 0) {
      forced <- new_candidates$key[1]
      values$forcedImage <- forced
      values$forcedCount <- 0
      return(get_next_image_pair())
    } else {
      if (!is.null(values$forcedImage)) {
        values$forcedImage <- NULL
        values$forcedCount <- 0
      }
    }

    # -- 3) Normal random logic with improvements
    available_indices <- which(!(documents$key %in% values$recent_images))
    if (length(available_indices) < 2) {
      values$recent_images <- character()
      available_indices <- seq_len(nrow(documents))
    }
    available_docs <- documents[available_indices, ]

    rand_num <- runif(1)

    # IMPROVEMENT 3: Add second chance mechanism (15% chance)
    if (rand_num < 0.15) {
      # Select images with high win rate but low total comparisons
      win_rate <- available_docs$wins / pmax(available_docs$total, 1)
      underexposed <- which(available_docs$total < quantile(available_docs$total, 0.3) & 
                           win_rate > 0.4)
      if (length(underexposed) > 0) {
        s1 <- sample(underexposed, 1)
        # Give them a shot at top-tier opponents
        top_indices <- which(available_docs$adjusted_elo >= quantile(available_docs$adjusted_elo, 0.8))
        if (length(top_indices) > 0) {
          s2 <- sample(top_indices, 1)
        } else {
          s2 <- sample(setdiff(seq_len(nrow(available_docs)), s1), 1)
        }
      } else {
        # Fallback to random selection
        sel <- sample(seq_len(nrow(available_docs)), 2)
        s1 <- sel[1]
        s2 <- sel[2]
      }
    } else if (rand_num < 0.40) {  # Adjusted from 0.25
      # 25%: fewest comparisons
      min_total <- quantile(available_docs$total, 0.02)
      candidates <- which(available_docs$total <= min_total)
      if (length(candidates) >= 2) {
        sel <- sample(candidates, 2)
      } else {
        sel <- sample(seq_len(nrow(available_docs)), 2)
      }
      s1 <- sel[1]
      s2 <- sel[2]
    } else if (rand_num < 0.75) {  # 35%: similar ELO (using adjusted_elo)
      idx <- sample(seq_len(nrow(available_docs)), 1)
      target_elo <- available_docs$adjusted_elo[idx]
      elo_diff <- abs(available_docs$adjusted_elo - target_elo)
      similar_indices <- which(elo_diff <= 100 & seq_len(nrow(available_docs)) != idx)
      if (length(similar_indices) == 0) {
        s2 <- sample(setdiff(seq_len(nrow(available_docs)), idx), 1)
      } else {
        s2 <- sample(similar_indices, 1)
      }
      s1 <- idx
    } else if (rand_num < 0.90) {  # 15%: high vs low ELO
      top_indices <- which(available_docs$adjusted_elo >= quantile(available_docs$adjusted_elo, 0.9))
      low_indices <- which(available_docs$adjusted_elo <= quantile(available_docs$adjusted_elo, 0.1))
      if (length(top_indices) > 0 && length(low_indices) > 0) {
        s1 <- sample(top_indices, 1)
        s2 <- sample(low_indices, 1)
      } else {
        sel <- sample(seq_len(nrow(available_docs)), 2)
        s1 <- sel[1]
        s2 <- sel[2]
      }
    } else {
      # 10%: new/promising images challenge top images
      low_total_threshold <- quantile(available_docs$total, 0.5)
      high_elo_threshold  <- quantile(available_docs$adjusted_elo, 0.5)
      low_total_indices   <- which(available_docs$total <= low_total_threshold)
      high_elo_indices    <- which(available_docs$adjusted_elo >= high_elo_threshold)
      promising_indices   <- intersect(low_total_indices, high_elo_indices)
      if (length(promising_indices) > 0) {
        s1 <- sample(promising_indices, 1)
      } else {
        s1 <- sample(seq_len(nrow(available_docs)), 1)
      }
      top_indices <- which(available_docs$adjusted_elo >= quantile(available_docs$adjusted_elo, 0.9))
      if (length(top_indices) > 0) {
        s2 <- sample(top_indices, 1)
      } else {
        s2 <- sample(setdiff(seq_len(nrow(available_docs)), s1), 1)
      }
    }

    # Ensure distinct
    if (s1 == s2) {
      s2 <- sample(setdiff(seq_len(nrow(available_docs)), s1), 1)
    }

    left  <- available_docs$key[s1]
    right <- available_docs$key[s2]

    # Update recent
    values$recent_images <- c(values$recent_images, left, right)
    if (length(values$recent_images) > 10) {
      values$recent_images <- tail(values$recent_images, 10)
    }

    list(left = left, right = right)
  }

  # Store the current pair
  current_pair <- reactiveVal()

  # Initialize the pair
  observeEvent(TRUE, {
    current_pair(get_next_image_pair())
  }, once = TRUE)

  # Render Left Image
  output$left_image <- renderImage({
    req(current_pair())
    pair <- current_pair()
    if (is.null(pair$left)) return(NULL)
    list(
      src        = file.path("www", "images", pair$left),
      contentType= "image/jpg",
      alt        = "Left Image"
    )
  }, deleteFile = FALSE)

  # Render Right Image
  output$right_image <- renderImage({
    req(current_pair())
    pair <- current_pair()
    if (is.null(pair$right)) return(NULL)
    list(
      src        = file.path("www", "images", pair$right),
      contentType= "image/jpg",
      alt        = "Right Image"
    )
  }, deleteFile = FALSE)

  # ================
  # 7. OBSERVERS
  # ================
  # --- 7A: Like Buttons
  observeEvent(input$left_like, {
    if (values$logged_in) {
      values$left_liked <- TRUE
      cat(values$username, "liked", current_pair()$left, "\n")
    }
  })

  observeEvent(input$right_like, {
    if (values$logged_in) {
      values$right_liked <- TRUE
      cat(values$username, "liked", current_pair()$right, "\n")
    }
  })

  # --- 7B: Purge Buttons
  observeEvent(input$left_purge, {
    req(values$logged_in)
    pair <- current_pair()
    if (!is.null(pair)) {
      purge_image(pair$left, values$username, conn)
      values$purged_left <- TRUE
      # If the right is already purged, both are purged => no rating => next pair
      if (values$purged_right) {
        # Both purged -> skip
        log_decision(
          user        = values$username,
          image1      = pair$left,
          image2      = pair$right,
          winner      = NULL,
          left_liked  = values$left_liked,
          right_liked = values$right_liked,
          conn        = conn_decision,
          reason      = "both purged"
        )
        advance_to_next_pair()
      }
      # else do nothing; remain on the same pair
    }
  })

  observeEvent(input$right_purge, {
    req(values$logged_in)
    pair <- current_pair()
    if (!is.null(pair)) {
      purge_image(pair$right, values$username, conn)
      values$purged_right <- TRUE
      # If left is already purged, both are purged => next pair
      if (values$purged_left) {
        log_decision(
          user        = values$username,
          image1      = pair$left,
          image2      = pair$right,
          winner      = NULL,
          left_liked  = values$left_liked,
          right_liked = values$right_liked,
          conn        = conn_decision,
          reason      = "both purged"
        )
        advance_to_next_pair()
      }
      # else remain on the same pair
    }
  })

  # --- 7C: Prefer Buttons
  #  If the chosen side is purged -> mistake => no ELO => next
  #  If the chosen side is not purged -> normal ELO => next
  observeEvent(input$left_button, {
    req(values$logged_in)
    pair <- current_pair()
    if (is.null(pair)) return(NULL)

    if (values$purged_left) {
      # Mistakenly preferred a purged item
      log_decision(
        user        = values$username,
        image1      = pair$left,
        image2      = pair$right,
        winner      = NULL,
        left_liked  = values$left_liked,
        right_liked = values$right_liked,
        conn        = conn_decision,
        reason      = "purged item chosen by mistake"
      )
      advance_to_next_pair()
    } else {
      # Normal ELO if left is not purged
      update_scores(pair$left, pair$right, conn)
      log_decision(
        user        = values$username,
        image1      = pair$left,
        image2      = pair$right,
        winner      = 1,
        left_liked  = values$left_liked,
        right_liked = values$right_liked,
        conn        = conn_decision
      )
      advance_to_next_pair()
    }
  })

  observeEvent(input$right_button, {
    req(values$logged_in)
    pair <- current_pair()
    if (is.null(pair)) return(NULL)

    if (values$purged_right) {
      # Mistakenly preferred a purged item
      log_decision(
        user        = values$username,
        image1      = pair$left,
        image2      = pair$right,
        winner      = NULL,
        left_liked  = values$left_liked,
        right_liked = values$right_liked,
        conn        = conn_decision,
        reason      = "purged item chosen by mistake"
      )
      advance_to_next_pair()
    } else {
      # Normal ELO if right is not purged
      update_scores(pair$right, pair$left, conn)
      log_decision(
        user        = values$username,
        image1      = pair$left,
        image2      = pair$right,
        winner      = 2,
        left_liked  = values$left_liked,
        right_liked = values$right_liked,
        conn        = conn_decision
      )
      advance_to_next_pair()
    }
  })
}

